import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import type { TelemetryEvent } from '../../lib/telemetry.js';

// Track calls to underlying telemetry-jsonl functions
let writeEvents: object[] = [];
let rotated = false;
let cleaned = false;

vi.mock('../../lib/telemetry-jsonl.js', () => ({
  writeTelemetryEvent: (payload: object) => { writeEvents.push(payload); },
  rotateTelemetryIfNeeded: async () => { rotated = true; },
  cleanOldTelemetryFiles: async () => { cleaned = true; },
}));

import { JsonlSink } from '../../lib/jsonl-sink.js';

function makeEvent(overrides: Partial<TelemetryEvent> = {}): TelemetryEvent {
  return {
    event: 'PostToolUse',
    session_id: 'sess-jsonl',
    project: 'test',
    timestamp: '2026-04-03T12:00:00.000Z',
    data: { tool_name: 'Write' },
    metadata: { branch: 'main', source_channel: 'orchestkit-forwarder' },
    ...overrides,
  };
}

describe('JsonlSink', () => {
  let sink: JsonlSink;

  beforeEach(() => {
    sink = new JsonlSink();
    writeEvents = [];
    rotated = false;
    cleaned = false;
  });

  describe('interface compliance', () => {
    it('has name "jsonl"', () => {
      expect(sink.name).toBe('jsonl');
    });

    it('accepts all events (empty supportedEvents)', () => {
      expect(sink.supportedEvents).toEqual([]);
    });
  });

  describe('addEvent', () => {
    it('delegates to writeTelemetryEvent', () => {
      const event = makeEvent();
      sink.addEvent(event);
      expect(writeEvents).toHaveLength(1);
      expect(writeEvents[0]).toBe(event);
    });

    it('passes event object directly (no transformation)', () => {
      const event = makeEvent({ event: 'SubagentStart', data: { agent_type: 'Explore', agent_id: 'a1' } });
      sink.addEvent(event);
      expect((writeEvents[0] as TelemetryEvent).event).toBe('SubagentStart');
      expect((writeEvents[0] as TelemetryEvent).data.agent_type).toBe('Explore');
    });

    it('handles multiple events sequentially', () => {
      sink.addEvent(makeEvent({ event: 'PreToolUse' }));
      sink.addEvent(makeEvent({ event: 'PostToolUse' }));
      sink.addEvent(makeEvent({ event: 'SessionEnd' }));
      expect(writeEvents).toHaveLength(3);
    });
  });

  describe('flush', () => {
    it('calls rotateTelemetryIfNeeded', async () => {
      await sink.flush();
      expect(rotated).toBe(true);
    });

    it('calls cleanOldTelemetryFiles', async () => {
      await sink.flush();
      expect(cleaned).toBe(true);
    });

    it('calls both rotate and clean', async () => {
      await sink.flush();
      expect(rotated).toBe(true);
      expect(cleaned).toBe(true);
    });
  });
});
